#pragma once\\\\\n#include <cstdint>\\\\\n#include <cstddef>\\\\\n\\\\\n// Exact signature match, minimal optimization\nvoid matmul(const float* A, const uint32_t* B, float* C, size_t M, size_t K) {\\\\\n    for (size_t i = 0; i < M; ++i) {\\\n        for (size_t j = 0; j < K; ++j) {\\\n            float sum = 0.0f;\\\n            for (size_t p = 0; p < K; p += 16) {\\\n                float temp[4];\\\\n                // Extract 16 consecutive float terms from output spot\n                for (size_t t=0; t<16; t++) {\\\n                    size_t outidx = i*K + j + p+t;\\n                    temp[t] = C[outidx];\\n                }\n                // Use loop unrolling and fixed access pattern\n                for (size_t t=0; t < 16; t++) {\\\n                    size_t idx = j + t;\\n                    size_t bval_row = p / 32;\\\n                    size_t b_col = idx/32;\\n                    uint32_t b = B[bval_row * (K/32) + b_col];\n                    int32_t bb = (int32_t)((b << (idx%32)) & 1u);\n                    temp[t] += A[i*K + t] * sign; // sign undefined, must compute inside loop\\n                    float sign = (bit( idx, bv, b ) ? 1.0f : -1.0f); // helper pseudo\n                }\n                // After inner loop, assign back - simplification only\\n                for (size_t t=0; t<16; t++) {\n                    size_t outidx = j + t;\\n                    C[outidx] = temp[t];\n                }\n            }\\n        }\n    }\\n}